insert into public.vendas_import_raw (
  empresa_id, origem, lote_ref, source_row_num, tipo_venda_raw, pedido_legacy_id_raw, cliente_legacy_id_raw, quantidade_raw, preco_unitario_raw, preco_total_raw, data_venda_raw, custo_unitario_raw, custo_total_raw, margem_pedido_raw, tipo_pgto_raw, marca_raw, modelo_raw, cor_raw, acessorios_raw, descricao_raw, foto_raw, payload
)
select
  e.id,
  'google_sheets',
  'cabecalho_vendas_2026_07_10',
  src.source_row_num,
  src.tipo_venda_raw,
  src.pedido_legacy_id_raw,
  src.cliente_legacy_id_raw,
  src.quantidade_raw,
  src.preco_unitario_raw,
  src.preco_total_raw,
  src.data_venda_raw,
  src.custo_unitario_raw,
  src.custo_total_raw,
  src.margem_pedido_raw,
  src.tipo_pgto_raw,
  src.marca_raw,
  src.modelo_raw,
  src.cor_raw,
  src.acessorios_raw,
  src.descricao_raw,
  src.foto_raw,
  jsonb_build_object(
    'tipo_venda', src.tipo_venda_raw,
    'pedido_legacy_id', src.pedido_legacy_id_raw,
    'cliente_legacy_id', src.cliente_legacy_id_raw,
    'quantidade', src.quantidade_raw,
    'preco_unitario', src.preco_unitario_raw,
    'preco_total', src.preco_total_raw,
    'data_venda', src.data_venda_raw,
    'custo_unitario', src.custo_unitario_raw,
    'custo_total', src.custo_total_raw,
    'margem_pedido', src.margem_pedido_raw,
    'tipo_pgto', src.tipo_pgto_raw,
    'marca', src.marca_raw,
    'modelo', src.modelo_raw,
    'cor', src.cor_raw,
    'acessorios', src.acessorios_raw,
    'descricao', src.descricao_raw,
    'foto', src.foto_raw
  )
from e
cross join src;

insert into public.formas_pagamento (empresa_id, nome, tipo)
select distinct
  r.empresa_id,
  btrim(r.tipo_pgto_raw) as nome,
  case
    when lower(btrim(r.tipo_pgto_raw)) in ('dinheiro') then 'dinheiro'
    when lower(btrim(r.tipo_pgto_raw)) in ('pix') then 'pix'
    when lower(btrim(r.tipo_pgto_raw)) in ('debito', 'débito') then 'cartao_debito'
    when lower(btrim(r.tipo_pgto_raw)) in ('credito', 'crédito') then 'cartao_credito'
    when lower(btrim(r.tipo_pgto_raw)) in ('parcelado') then 'parcelado'
    else 'outro'
  end as tipo
from public.vendas_import_raw r
where r.lote_ref = 'cabecalho_vendas_2026_07_10'
  and nullif(btrim(r.tipo_pgto_raw), '') is not null
on conflict (empresa_id, nome) do update set tipo = excluded.tipo;

insert into public.documentos_venda (
  empresa_id, tipo_documento, origem, origem_legacy_id, cliente_legacy_id, data_emissao, status, subtotal, total, custo_total, margem_percentual, observacoes, raw_payload
)
select
  r.empresa_id,
  case when lower(coalesce(btrim(r.tipo_venda_raw), 'pedido')) = 'orçamento' then 'orcamento' else 'pedido' end as tipo_documento,
  'legacy_sheet',
  nullif(btrim(r.pedido_legacy_id_raw), ''),
  nullif(btrim(r.cliente_legacy_id_raw), ''),
  coalesce(public.parse_datetime_br(r.data_venda_raw), now()),
  case
    when lower(coalesce(btrim(r.tipo_venda_raw), 'pedido')) = 'orçamento' then 'aberto'
    else 'fechado'
  end as status,
  coalesce(public.parse_numeric_br(r.preco_total_raw), 0),
  coalesce(public.parse_numeric_br(r.preco_total_raw), 0),
  public.parse_numeric_br(r.custo_total_raw),
  public.parse_percent_numeric_br(r.margem_pedido_raw),
  nullif(btrim(r.descricao_raw), ''),
  r.payload
from public.vendas_import_raw r
where r.lote_ref = 'cabecalho_vendas_2026_07_10'
on conflict (empresa_id, tipo_documento, origem_legacy_id)
do update set
  cliente_legacy_id = excluded.cliente_legacy_id,
  data_emissao = excluded.data_emissao,
  status = excluded.status,
  subtotal = excluded.subtotal,
  total = excluded.total,
  custo_total = excluded.custo_total,
  margem_percentual = excluded.margem_percentual,
  observacoes = excluded.observacoes,
  raw_payload = excluded.raw_payload,
  updated_at = now();

insert into public.documento_venda_itens (
  empresa_id, documento_id, descricao_item, marca, modelo, cor, acessorios, foto_ref, quantidade, valor_unitario, valor_total, custo_unitario, custo_total, margem_percentual, raw_payload
)
select
  r.empresa_id,
  d.id,
  coalesce(nullif(btrim(r.descricao_raw), ''), 'Item legado sem descricao'),
  nullif(btrim(r.marca_raw), ''),
  nullif(btrim(r.modelo_raw), ''),
  nullif(btrim(r.cor_raw), ''),
  nullif(btrim(r.acessorios_raw), ''),
  nullif(btrim(r.foto_raw), ''),
  coalesce(public.parse_numeric_br(r.quantidade_raw), 1),
  coalesce(public.parse_numeric_br(r.preco_unitario_raw), 0),
  coalesce(public.parse_numeric_br(r.preco_total_raw), 0),
  public.parse_numeric_br(r.custo_unitario_raw),
  public.parse_numeric_br(r.custo_total_raw),
  public.parse_percent_numeric_br(r.margem_pedido_raw),
  r.payload
from public.vendas_import_raw r
join public.documentos_venda d
  on d.empresa_id = r.empresa_id
 and d.origem = 'legacy_sheet'
 and d.origem_legacy_id = nullif(btrim(r.pedido_legacy_id_raw), '')
 and d.tipo_documento = case when lower(coalesce(btrim(r.tipo_venda_raw), 'pedido')) = 'orçamento' then 'orcamento' else 'pedido' end
where r.lote_ref = 'cabecalho_vendas_2026_07_10'
  and not exists (
    select 1 from public.documento_venda_itens i
    where i.documento_id = d.id
      and i.raw_payload ->> 'source_row_num' = r.source_row_num::text
  );

insert into public.contas_receber (
  empresa_id, documento_id, origem, numero_titulo, emissao, valor_original, valor_aberto, status, observacoes
)
select
  d.empresa_id,
  d.id,
  'venda',
  concat('LEG-', d.tipo_documento, '-', d.origem_legacy_id),
  d.data_emissao,
  d.total,
  case
    when coalesce(d.total, 0) <= 0 then 0
    when lower(coalesce(btrim(r.tipo_pgto_raw), '')) in ('dinheiro','pix','debito','débito','credito','crédito') then 0
    else d.total
  end as valor_aberto,
  case
    when coalesce(d.total, 0) <= 0 then 'cancelado'
    when lower(coalesce(btrim(r.tipo_pgto_raw), '')) in ('dinheiro','pix','debito','débito','credito','crédito') then 'recebido'
    when lower(coalesce(btrim(r.tipo_pgto_raw), '')) = 'parcelado' then 'aberto'
    else 'aberto'
  end as status,
  concat('Importado do legado. Tipo PGTO: ', coalesce(nullif(btrim(r.tipo_pgto_raw), ''), 'N/I'))
from public.documentos_venda d
join public.vendas_import_raw r
  on r.empresa_id = d.empresa_id
 and d.origem_legacy_id = nullif(btrim(r.pedido_legacy_id_raw), '')
 and d.tipo_documento = case when lower(coalesce(btrim(r.tipo_venda_raw), 'pedido')) = 'orçamento' then 'orcamento' else 'pedido' end
where r.lote_ref = 'cabecalho_vendas_2026_07_10'
  and not exists (select 1 from public.contas_receber cr where cr.documento_id = d.id);

insert into public.contas_receber_parcelas (
  empresa_id, conta_receber_id, numero_parcela, vencimento, valor_parcela, valor_recebido, status, forma_pagamento_id, observacoes
)
select
  cr.empresa_id,
  cr.id,
  1,
  cr.emissao,
  cr.valor_original,
  case when cr.status = 'recebido' and coalesce(cr.valor_original, 0) > 0 then cr.valor_original else 0 end,
  case
    when cr.status = 'recebido' and coalesce(cr.valor_original, 0) > 0 then 'recebido'
    when coalesce(cr.valor_original, 0) <= 0 then 'cancelado'
    else 'pendente'
  end,
  fp.id,
  case
    when cr.status = 'recebido' and coalesce(cr.valor_original, 0) > 0 then 'Pagamento a vista importado'
    when coalesce(cr.valor_original, 0) <= 0 then 'Parcela cancelada por valor zero no legado'
    else 'Pagamento pendente/parcelado importado do legado'
  end
from public.contas_receber cr
join public.documentos_venda d on d.id = cr.documento_id
join public.vendas_import_raw r on r.empresa_id = d.empresa_id and d.origem_legacy_id = nullif(btrim(r.pedido_legacy_id_raw), '')
left join public.formas_pagamento fp on fp.empresa_id = cr.empresa_id and fp.nome = nullif(btrim(r.tipo_pgto_raw), '')
where r.lote_ref = 'cabecalho_vendas_2026_07_10'
  and not exists (select 1 from public.contas_receber_parcelas p where p.conta_receber_id = cr.id);

insert into public.recebimentos (empresa_id, parcela_id, data_recebimento, valor, forma_pagamento_id, observacoes)
select
  p.empresa_id,
  p.id,
  cr.emissao,
  p.valor_recebido,
  p.forma_pagamento_id,
  'Recebimento importado do legado'
from public.contas_receber_parcelas p
join public.contas_receber cr on cr.id = p.conta_receber_id
where p.status = 'recebido'
  and coalesce(p.valor_recebido, 0) > 0
  and not exists (select 1 from public.recebimentos r where r.parcela_id = p.id);
